diagram.mermaid:
classDiagram
  class Signature {
    +input_fields
    +output_fields
  }
  class Module {
    +signatures
    +forward()
  }
  class Teleprompter {
    +metric
    +compile(module)
    +few_shot_examples
  }
  Module --> Signature
  Teleprompter --> Module : optimises

classDiagram
  class Record {
    +id
    +material_type
    +common_fields
  }
  class YarnExt {
    +weight
    +fiber
  }
  class FabricExt {
    +width
    +weave
  }
  Record o-- YarnExt : yarn
  Record o-- FabricExt : fabric

classDiagram
  class Envelope {
    +schema_version
    +type
    +payload
  }
  class Extensions {
    +x-vendor.foo
    +x-vendor.bar
  }
  Envelope o-- Extensions : extensions
  note for Envelope "Old clients ignore unknown extensions;\nschema_version bump = breaking change"
